// Outputs: [response, persist-trigger, metric-request, metric-completed, metric-error]
const body = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};
if (!body.agreementId || !body.assetId) {
    msg.statusCode = 422;
    msg.payload = { detail: 'agreementId and assetId are required' };
    msg.headers = { 'Content-Type': 'application/json' };
    return [msg, null, null, null, null];
}
const format = body.format || 'http-pull';
if (format !== 'http-pull' && format !== 'kafka-streaming') {
    msg.statusCode = 422;
    msg.payload = { detail: 'format must be http-pull or kafka-streaming' };
    msg.headers = { 'Content-Type': 'application/json' };
    return [msg, null, null, null, null];
}

function isoUtcWithOffset(d) {
    // Python isoformat() on UTC-aware datetime emits microsecond precision
    // and `+00:00` suffix. JS toISOString() emits ms precision and `Z`. Pad
    // and swap to match exactly.
    return d.toISOString().slice(0, -1) + '000+00:00';
}

function provisionHttpPull(transfer) {
    const secret = env.get('DSP_HMAC_SECRET');
    const baseUrl = (env.get('DSP_DATA_API_BASE_URL') || 'https://ai-insight.facis.cloud').replace(/\/$/, '');
    const ttl = Number(env.get('DSP_DEFAULT_TTL_SECONDS') || '3600');
    if (!secret) throw new Error('DSP_HMAC_SECRET unset');
    const path = '/api/data/' + transfer.assetId;
    const fromTs = (transfer.parameters && transfer.parameters.windowFrom) || '';
    const toTs = (transfer.parameters && transfer.parameters.windowTo) || '';
    const expiresAt = isoUtcWithOffset(new Date(Date.now() + ttl * 1000));
    const message = 'GET:' + path + ':' + fromTs + ':' + toTs + ':' + expiresAt;
    const token = crypto.createHmac('sha256', Buffer.from(secret, 'utf8'))
                        .update(message, 'utf8').digest('hex');
    return {
        url: baseUrl + path + '?from=' + fromTs + '&to=' + toTs + '&expiresAt=' + expiresAt + '&sig=' + token,
        token: token,
        expiresAt: expiresAt,
        bootstrap: null, topic: null, sasl: null
    };
}

function provisionKafka(transfer) {
    const bootstrap = env.get('DSP_KAFKA_BOOTSTRAP') || 'kafka.provider.example:9092';
    const ttl = Number(env.get('DSP_DEFAULT_TTL_SECONDS') || '3600');
    const password = crypto.randomBytes(24).toString('base64url'); // matches secrets.token_urlsafe(24)
    return {
        url: null, token: null,
        bootstrap: bootstrap,
        // Python: f"iot.dataset.{assetId}.tp-{transfer.id}" where transfer.id already starts with 'tp-'
        // → output literally contains 'tp-tp-{12hex}'. Preserved verbatim.
        topic: 'iot.dataset.' + transfer.assetId + '.tp-' + transfer.id,
        sasl: { mechanism: 'SCRAM-SHA-256', username: 'user_' + transfer.id, password: password },
        expiresAt: isoUtcWithOffset(new Date(Date.now() + ttl * 1000))
    };
}

const now = isoUtcWithOffset(new Date());
const transferId = 'tp-' + crypto.randomBytes(6).toString('hex');
const transfer = {
    id: transferId,
    agreementId: body.agreementId,
    assetId: body.assetId,
    format: format,
    state: 'REQUESTED',
    access: null,
    reason: null,
    parameters: body.parameters || {},
    createdAt: now,
    updatedAt: now
};

// Auto-complete: REQUESTED → STARTED → COMPLETED with access provisioning.
// Mirrors transfer_store.start_and_complete() at transfer_store.py:134-137.
let metricCompleted = null;
let metricError = null;
try {
    transfer.state = 'STARTED';
    transfer.updatedAt = isoUtcWithOffset(new Date());
    const access = format === 'http-pull' ? provisionHttpPull(transfer) : provisionKafka(transfer);
    transfer.state = 'COMPLETED';
    transfer.access = access;
    transfer.updatedAt = isoUtcWithOffset(new Date());
    metricCompleted = { payload: { family: 'facis_dsp_transfer_completions_total' } };
    node.log('Transfer ' + transferId + ' COMPLETED (' + format + ')');
} catch (err) {
    transfer.state = 'ERROR';
    transfer.reason = String(err && err.message ? err.message : err);
    transfer.updatedAt = isoUtcWithOffset(new Date());
    metricError = { payload: { family: 'facis_dsp_transfer_errors_total' } };
    node.error('Transfer ' + transferId + ' ERROR: ' + transfer.reason);
}

const transfers = flow.get('transfers') || {};
transfers[transferId] = transfer;
flow.set('transfers', transfers);

msg.payload = { transferId: transferId };
msg.headers = { 'Content-Type': 'application/json' };
msg.statusCode = 202;

const metricRequested = { payload: { family: 'facis_dsp_transfer_requests_total', label: format } };
return [msg, { payload: '' }, metricRequested, metricCompleted, metricError];

const transfers = flow.get('transfers') || {};
const id = msg.req.params.id;
const found = transfers[id];
if (!found) {
    msg.statusCode = 404;
    msg.payload = { detail: 'Transfer ' + id + ' not found' };
} else {
    msg.statusCode = 200;
