const VALID = {
    REQUESTED: new Set(['STARTED','TERMINATED','ERROR']),
    STARTED:   new Set(['COMPLETED','SUSPENDED','TERMINATED','ERROR']),
    SUSPENDED: new Set(['STARTED','TERMINATED']),
    COMPLETED: new Set(),
    TERMINATED: new Set(),
    ERROR:     new Set()
};
const id = msg.req.params.id;
const transfers = flow.get('transfers') || {};
const cur = transfers[id];
if (!cur) {
    msg.statusCode = 404;
    msg.payload = { detail: 'Transfer ' + id + ' not found' };
    msg.headers = { 'Content-Type': 'application/json' };
    return [msg, null];
}
const target = 'SUSPENDED';
const allowed = VALID[cur.state] || new Set();
if (!allowed.has(target)) {
    msg.statusCode = 400;
    msg.payload = { detail: 'Invalid transition: ' + cur.state + ' \u2192 ' + target +
                            '. Valid targets: ' + (Array.from(allowed).join(',') || '(terminal)') };
    msg.headers = { 'Content-Type': 'application/json' };
    return [msg, null];
}
const now = new Date().toISOString().slice(0, -1) + '000+00:00';
const updated = Object.assign({}, cur, { state: target, reason: 'Suspended by consumer', updatedAt: now });
transfers[id] = updated;
flow.set('transfers', transfers);
msg.statusCode = 200;
msg.payload = updated;
msg.headers = { 'Content-Type': 'application/json' };
return [msg, { payload: '' }];

